5	const basePremium = (type: string): number => {
6	  if (type === "amulet") return 60;
7	  if (type === "staff") return 80;
8	  return 100;
9	};
10	
11	const roundUp = (value: number): number => {
12	  const epsilon = 1e-9;
13	  return Math.ceil(value - epsilon);
14	};
15	
16	const FIRST_INSURANCE_SURCHARGE = 1.1;
17	const PROCESSING_FEE = 5;
18	
19	export const run = (input: Input): unknown => {
20	  const results = input.steps.map((step) => {
21	    const base = basePremium(step.items[0].type);
22	    const withFirstInsurance = base * FIRST_INSURANCE_SURCHARGE;
23	    const premium = roundUp(withFirstInsurance) + PROCESSING_FEE;
24	    return { premium };
25	  });
26	  return { results };
27	};
